P GetClaimAge     B
D GetClaimAge     PI
D*----------------------------------------------------------------
D Age             S              9  0
C*****************************************************************
   Monitor;
      If G7324A = '1';
         Age = %Diff(%Date(G71090:*Iso):%Date(G71080:*Iso):*M);
      Else;
         Age = %Diff(%Date(G71090:*Iso):%Date(G7325A:*Eur):*M);
      EndIf;
   On-Error *All;
         Age = 100;
   EndMon;
   If Age > 99;
      KLMTH = 99;
   Else;
      KLMTH = Age;
   EndIf;
P GetClaimAge     E
